var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"큭?! 일격 한 번에 무기가...!","JPN":"くっ！？　一撃で武器が……！","ENG":"Kgh?! My weapon... shattered in a single strike...?!","TWN":"咳？！只發動一擊武器就……！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"거기까지다.","JPN":"ここまでだ。","ENG":"That's enough.","TWN":"到此為止。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"레아 님!","JPN":"レア様！","ENG":"Ms. Leah!","TWN":"蕾亞！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이건 진짜...","JPN":"これはマジで……","ENG":"She's seriously...","TWN":"這也太……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...더럽게 강하잖아.","JPN":"……強すぎる。","ENG":"...insanely strong.","TWN":"……厲害了吧。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"안... 돼.","JPN":"ダ……メ。","ENG":"No...!","TWN":"不……行。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"미안하구나, 아우드라.","JPN":"すまない、アウドラ。","ENG":"I'm sorry, Audra.","TWN":"對不起，奧德拉。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"좀 더 일찍 결단을 내렸어야 했는데, 내가 너무 늦게 와버렸어.","JPN":"もっと早く決断すべきだったが、遅くなりすぎてしまった。","ENG":"I should have made the decision sooner, but I came too late.","TWN":"我應該更早下定決心的，是我來得太晚了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"해는 아직 저물지 않은 걸요.","JPN":"まだ日は暮れていません。","ENG":"The sun has not set yet.","TWN":"太陽還沒有落下呢。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"늦지 않았어요. 이번에도.","JPN":"まだ間に合います。今回も。","ENG":"It's not too late. Not this time either.","TWN":"這次也不算晚。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"해?","JPN":"日？","ENG":"The sun?","TWN":"太陽？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"그러고 보니, 지난 번에도 이 무렵에...","JPN":"そういえば、この前もこの時間に……","ENG":"Come to think of it, last time it was around this time as well...","TWN":"這麼說來，上次也是在這個時候……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...헉!","JPN":"……はっ！","ENG":"...Kuh!","TWN":"……啊！"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"좋은 아침이구나, 레아야.","JPN":"おはよう、レア。","ENG":"Good morning, Leah.","TWN":"早安，蕾亞。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"엄마? 여긴... 집이네요?","JPN":"お母さん？　ここは……家だよね？","ENG":"Mom? This is... home?","TWN":"媽媽？這裡是……家？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"전 분명... 죽었다고 생각했는데. 눈을 떠보니 여기에 있어요.","JPN":"絶対……死んだと思ったのに。目覚めたらここにいたの。","ENG":"I was sure... I had died. But when I opened my eyes, I was here.","TWN":"我明明以為自己已經死了。可是一睜開雙眼，就回到這裡了。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"낙원에서는 모든 것의 시작과 끝이 맞닿은 채 순환한단다.","JPN":"楽園ではどんなものでも始まりと終わりが繋がって循環しているわ。","ENG":"In the Promised Land, the beginning and end of everything meet and repeat in a cycle.","TWN":"在樂園裡，一切的開始與終結都彼此相連並循環。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"생과 죽음 역시도 마찬가지지.","JPN":"生と死も同じ。","ENG":"Life and death are no exception.","TWN":"生與死也是如此。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...하루가 지나면, 죽음이고 뭐고 전부 없었던 일이 된다는 말씀이세요?","JPN":"……一日が終われば、死も何もかもが全部なかったことになるってこと？","ENG":"...So after a day passes, death and everything else are simply undone?","TWN":"……也就是說，只要過了一天，死亡之類的事情會像從未發生過一樣？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"하나 예외가 있다면, 우리 모두 오늘과 그 다음 오늘이 서로 다른 오늘이란 걸 기억하고 있다는 점이지.","JPN":"一つだけ例外があるとすれば、みんなが今日とその次の今日を別の日として覚えているところね。","ENG":"The only exception is that we all remember that today and the next today are different days.","TWN":"唯一的例外，是我們所有人都記得，今天與下一個今天其實是不同的今天。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"모든 사람들의 마음엔 잊고 싶지 않아하는 소망이 있으니까.","JPN":"誰の心にも忘れたくない願いがあるから。","ENG":"Because everyone has a wish they don't want to forget.","TWN":"因為每個人的心裡，都有不願忘記的願望。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"소망이라...","JPN":"願いか……","ENG":"A wish...","TWN":"願望嗎……"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"만약 제가 지금 낙원을 떠나게 된다면, 그 다음엔 어떻게 되죠?","JPN":"もし私が今楽園を出たら、その後はどうなるのかな？","ENG":"If I were to leave the Promised Land right now, what would happen then?","TWN":"如果我現在離開樂園，之後會怎麼樣？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"네가 어디에 있든, 오늘이 지나면 다시 이곳에서 눈을 뜨겠지.","JPN":"あなたがどこにいても、今日が過ぎたらまたここで目覚めることになるわ。","ENG":"No matter where you are, once today ends, you will wake up here again.","TWN":"無論你在哪裡，只要今天結束，明天你依然會在這裡醒來。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"너 역시 낙원의 주민이니까.","JPN":"あなたも楽園の住民だから。","ENG":"Because you are also a resident of the Promised Land.","TWN":"因為你也是樂園的居民。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"낙원에서 벗어나는 게... 제 소망이라고 해도 말인가요?","JPN":"楽園から出るのが……私の願いだとしても？","ENG":"Even if my wish is... to escape the Promised Land?","TWN":"就算……離開樂園是我的願望也一樣嗎？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"그 질문은 네 스스로에게 해봐야지.","JPN":"その質問は、あなた自身にしないと。","ENG":"That is something you must ask yourself.","TWN":"那個問題，應該由你自己回答。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"레아야. 넌 정말 이곳을 떠나고 싶은 게 맞니?","JPN":"レア。あなたは本当にここから出たいの？","ENG":"Leah, do you truly wish to leave this place?","TWN":"蕾亞，你真的想離開這裡嗎？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};